func:
msg.topic = 'tipa-monitor-stats';
var startTime = flow.get('start_time');
if (!startTime) { startTime = Date.now(); flow.set('start_time', startTime); }
msg.payload = {
    jde_queries: flow.get('jde_query_count') || 0,
    ocr_count: flow.get('ocr_count') || 0,
    ocr_pub: flow.get('ocr_pub') || 0,
    topics_total: Object.keys(global.get('tipa_uns_discovered') || {}).length,
    uptime_s: Math.floor((Date.now() - startTime) / 1000),
    ts: new Date().toISOString()
};
return msg;

var topic = msg.topic;
if (!topic || topic.indexOf('tipa/') !== 0) return msg;
var discovered = global.get('tipa_uns_discovered') || {};
discovered[topic] = {ts: new Date().toISOString(), sample: String(msg.payload || '').slice(0, 80)};
global.set('tipa_uns_discovered', discovered);

var tree = global.get('tipa_uns_tree') || {};
var parts = topic.split('/');
var cur = tree;
parts.forEach(function(p, i) {
    if (!cur[p]) cur[p] = {};
    if (i === parts.length - 1) {
        cur[p]._discovered = true;
        cur[p]._last_seen = discovered[topic].ts;
    }
    cur = cur[p];
});
global.set('tipa_uns_tree', tree);
flow.set('uns_tree', tree);
return msg;

// Filter incoming MQTT messages for the selected UNS node
var filter = flow.get('uns_live_filter') || '';
if (!filter) return msg;

var topic = msg.topic || '';
// Match: exact, wildcard +, wildcard #
var filterBase = filter.replace(/\/\+$/, '').replace(/\/#$/, '');
if (topic.indexOf(filterBase) === 0) {
    // Forward to JDE UI as live message
    var payload = msg.payload;
    if (typeof payload === 'object') {
        try { payload = JSON.stringify(payload); } catch(e) { payload = String(payload); }
    }
    msg.topic = 'tipa-uns-live';
    msg.payload = {topic: topic, payload: String(payload).slice(0, 500)};
    return msg;
}
return null;

var ev = msg.topic;
var ECHO = ['obj-type-saved','obj-types-list','obj-ingest-result','obj-mapping-saved','obj-mapping-loaded','obj-list','obj-uns-cfg','obj-uns-cfg-saved'];
if (ECHO.indexOf(ev) >= 0) return [null,null,null,null,null,null,null];

node.warn('[OBJ] ' + ev);

if (ev === 'obj-save-type')    return [msg,null,null,null,null,null,null];
if (ev === 'obj-load-types')   return [null,msg,null,null,null,null,null];
if (ev === 'obj-ingest')       return [null,null,msg,null,null,null,null];
if (ev === 'obj-save-mapping') return [null,null,null,msg,null,null,null];
if (ev === 'obj-load-mapping') return [null,null,null,null,msg,null,null];
if (ev === 'obj-load-list')    return [null,null,null,null,null,msg,null];
if (ev === 'obj-save-uns-cfg' || ev === 'obj-load-uns-cfg') return [null,null,null,null,null,null,msg];

node.warn('[OBJ] unknown topic: ' + ev);
return [null,null,null,null,null,null,null];

// Save object_type AND auto-create per-type table uns_obj_<id> (key_value, attribute)
var d = msg.payload || {};
if (!d.object_type_id) return null;

var safe = String(d.object_type_id || '').toLowerCase().replace(/[^a-z0-9_]/g, '_');
if (!safe || /^[0-9]/.test(safe)) {
    node.error('Invalid object_type_id (must start with letter, [a-z0-9_]): ' + d.object_type_id);
    return null;
}
var tbl    = 'uns_obj_' + safe;
var idxUpd = 'idx_' + tbl + '_updated';
var idxAtt = 'idx_' + tbl + '_attribute';

// FIX 42601 — pg driver KHÔNG support multi-statement khi có $1...$N parameters.
// Solution: gộp toàn bộ CREATE TABLE / CREATE INDEX vào DO $$ ... $$ block (1 statement, no params),
// rồi nối với INSERT (có params) qua dấu ; — DO block không bị engine parse như SQL thường mà
// chạy trong PL/pgSQL context. Statement count cho parser ngoài: 2 → vẫn lỗi.
//
// Cách an toàn nhất: chỉ giữ INSERT ... RETURNING làm câu duy nhất với params,
// nhúng CREATE TABLE / INDEX vào trong cùng INSERT bằng CTE + DO block KHÔNG được — DDL không cho
// chạy trong CTE. Vậy tách thành 2 chuỗi gửi nối tiếp:
//   Statement 1 (no params): DO $$ … all DDL … $$;
//   Statement 2 (with params): INSERT ... ON CONFLICT ... RETURNING
//
// Thực hiện: dùng DO block để wrap DDL idempotent (dynamic SQL), sau đó thêm `;` rồi INSERT.
// pg driver thực ra chấp nhận 1 SEMICOLON-separated query string khi `extended query` không có
// param? — KHÔNG. Khi msg.params có $N, postgres node dùng extended protocol = single statement only.
//
// → Solution chuẩn: bỏ DDL khỏi câu này. Đẩy DDL vào fn_obj_ddl (đã có "Init objects DDL" inject)
// đảm nhiệm migrate-or-create. fn_obj_save_type chỉ INSERT object_types.
// fn_obj_ddl đã có DO $do$ ... LOOP qua object_types tạo bảng — nhưng nó chỉ chạy khi user trigger
// inject node. → Sau khi save type mới, ta phải tự trigger DDL.
//
// Cách đơn giản nhất: dùng DO block có dynamic SQL để tạo bảng, gửi LÀM CÂU RIÊNG (no params).
// Output 2 outputs từ function này: [DDL no-params, INSERT with-params].
// Mỗi đi qua PG node 1 lần, theo thứ tự — nhưng cùng wire vào 1 PG node cũng OK vì 2 messages tuần tự.
//
// → Implement: split into 2 messages, send through pg node sequentially.

// Message 1: pure DDL, no params (DO block accepts dynamic SQL safely)
var msgDdl = {
    query:
        "DO $do$ BEGIN " +
        "  EXECUTE format('CREATE TABLE IF NOT EXISTS public.%I (" +
        "    key_value  VARCHAR(100) PRIMARY KEY, " +
        "    attribute  JSONB, " +
        "    created_at TIMESTAMP DEFAULT NOW(), " +
        "    updated_at TIMESTAMP DEFAULT NOW())', '" + tbl + "'); " +
        "  EXECUTE format('CREATE INDEX IF NOT EXISTS %I ON public.%I(updated_at DESC)', " +
        "                 '" + idxUpd + "', '" + tbl + "'); " +
        "  EXECUTE format('CREATE INDEX IF NOT EXISTS %I ON public.%I USING GIN (attribute)', " +
        "                 '" + idxAtt + "', '" + tbl + "'); " +
        "END $do$;",
    params:  [],
    payload: null,
    _ddl_only: true   // marker — finalize node will skip emitting result
};

// Message 2: INSERT with params (carries _saved_id/_saved_tbl for downstream)
var msgIns = {
    query:
        "INSERT INTO public.object_types (object_type_id, object_type_name, description, attributes) " +
        "VALUES ($1,$2,$3,$4::jsonb) " +
        "ON CONFLICT (object_type_id) DO UPDATE SET " +
        "  object_type_name = EXCLUDED.object_type_name, " +
        "  description      = EXCLUDED.description, " +
        "  attributes       = EXCLUDED.attributes " +
        "RETURNING object_type_code",
    params: [
        safe,
        d.object_type_name || '',
        d.description || '',
        JSON.stringify(d.attributes || [])
    ],
    payload:    null,
    _saved_id:  safe,
    _saved_tbl: tbl
};

node.warn('[OBJ] Saving type=' + safe + ' (DDL→' + tbl + ' then INSERT object_types)');
// Send DDL first, then INSERT — both go through same PG node downstream
node.send(msgDdl);
return msgIns;

msg.topic = 'obj-type-saved';
if (msg.error) {
    msg.payload = { ok:false, msg: String(msg.error).slice(0, 250) };
} else {
    var rows = msg.payload || [];
    var code = rows.length && rows[0].object_type_code;
    msg.payload = {
        ok: true,
        msg: 'Saved type=' + (msg._saved_id || '') +
             ' table=' + (msg._saved_tbl || '') +
             (code ? ' (code #' + code + ')' : ''),
        object_type_id:   msg._saved_id,
        object_type_code: code,
        table_name:       msg._saved_tbl
    };
}
return msg;

msg.query = 'SELECT object_type_id, object_type_code, object_type_name, description, attributes, created_at::text as created_at FROM public.object_types ORDER BY object_type_code';
msg.params = [];
msg.payload = null;
return msg;

msg.topic = 'obj-types-list';
msg.payload = msg.payload || [];
return msg;

// UI manual ingest — uses mapping for key_value extraction unless explicit
var d = msg.payload || {};
var object_type = d.object_type;
var content     = d.content;
var explicit_id = d.object_id;  // UI sends 'object_id' field — map to key_value

if (!object_type) {
    node.send([null, { topic:'obj-ingest-result', payload:{ ok:false, msg:'Missing object_type' }}]);
    return null;
}
if (!content || typeof content !== 'object') {
    node.send([null, { topic:'obj-ingest-result', payload:{ ok:false, msg:'Missing or invalid content' }}]);
    return null;
}

var safe = String(object_type).toLowerCase().replace(/[^a-z0-9_]/g, '_');
var tbl  = 'uns_obj_' + safe;

if (explicit_id) {
    msg.query = 'INSERT INTO public.' + tbl + ' (key_value, attribute) ' +
                'VALUES ($1::varchar, $2::jsonb) ' +
                'ON CONFLICT (key_value) DO UPDATE SET ' +
                '  attribute  = EXCLUDED.attribute, ' +
                '  updated_at = NOW()';
    msg.params = [String(explicit_id), JSON.stringify(content)];
    msg.payload = null;
    msg._ingest_result = { ok:true, msg:'Saved public.' + tbl + '/' + explicit_id + ' (explicit)' };
    return [msg, null];
}

msg._seed_type    = object_type;
msg._seed_content = content;
msg.query  = 'SELECT id_path FROM public.object_mappings WHERE object_type_id = $1 AND mapping_name = $2 LIMIT 1';
msg.params = [object_type, 'default'];
msg.payload = null;
return [null, msg];

msg.topic = 'obj-ingest-result';
if (msg.error) {
    msg.payload = { ok:false, msg: String(msg.error).slice(0,150) };
} else {
    msg.payload = msg._ingest_result || { ok:true, msg:'Done' };
}
return msg;

var d = msg.payload || {};
if (!d.object_type_id) return null;
if (!d.id_path) {
    // Validation error — skip PG, go directly to UI (output 1)
    msg.topic = 'obj-mapping-saved';
    msg.payload = { ok:false, msg: 'id_path is required — define JSON path to extract object_id' };
    return [null, msg];
}
var name = d.mapping_name || 'default';
msg.query = 'INSERT INTO public.object_mappings (object_type_id, mapping_name, rules, id_path) VALUES ($1,$2,$3::jsonb,$4) ON CONFLICT (object_type_id, mapping_name) DO UPDATE SET rules=EXCLUDED.rules, id_path=EXCLUDED.id_path, updated_at=NOW()';
msg.params = [d.object_type_id, name, JSON.stringify(d.rules || []), d.id_path];
msg.payload = null;
msg._saved = d.object_type_id + '/' + name;
return [msg, null];

// If upstream already set topic+payload (validation error), pass through
if (msg.topic === 'obj-mapping-saved' && msg.payload) return msg;
msg.topic = 'obj-mapping-saved';
if (msg.error) msg.payload = { ok:false, msg: String(msg.error).slice(0,150) };
else msg.payload = { ok:true, msg: 'Saved mapping ' + (msg._saved||'') };
return msg;

var d = msg.payload || {};
msg.query = 'SELECT mapping_name, rules, id_path FROM public.object_mappings WHERE object_type_id = $1 AND mapping_name = $2';
msg.params = [d.object_type_id, d.mapping_name || 'default'];
msg.payload = null;
return msg;

msg.topic = 'obj-mapping-loaded';
var rows = msg.payload || [];
if (!rows.length) { msg.payload = { mapping_name:'default', rules:[], id_path:'' }; return msg; }
var r = rows[0];
var rules = r.rules;
if (typeof rules === 'string') { try { rules = JSON.parse(rules); } catch(e) { rules = []; } }
msg.payload = {
    mapping_name: r.mapping_name,
    rules: rules || [],
    id_path: r.id_path || ''
};
return msg;

// Browse rows from public.uns_obj_<type>
// Alias key_value→object_id, attribute→content_object để UI hiện tại không phải đổi
var d = msg.payload || {};
if (d.object_type) {
    var safe = String(d.object_type).toLowerCase().replace(/[^a-z0-9_]/g, '_');
    var tbl  = 'uns_obj_' + safe;
    msg.query = "SELECT $1::text AS object_type_id, " +
                "       key_value AS object_id, " +
                "       attribute AS content_object, " +
                "       created_at::text AS created_at, " +
                "       updated_at::text AS updated_at " +
                "FROM public." + tbl + " " +
                "ORDER BY updated_at DESC LIMIT 500";
    msg.params = [d.object_type];
} else {
    // No type — return empty (UI now requires type)
    msg.query  = "SELECT NULL::text AS object_type_id, NULL::varchar AS object_id, " +
                 "NULL::jsonb AS content_object, NULL::text AS created_at, NULL::text AS updated_at " +
                 "WHERE false";
    msg.params = [];
}
msg.payload = null;
return msg;

msg.topic = 'obj-list';
msg.payload = msg.payload || [];
return msg;

// Topic: tipa/hcm/plant1/{domain}/{object_type}
// object_type = last segment of topic
// object_id extracted from payload using MAPPING stored in DB (NOT hardcoded)
var topic = msg.topic || '';
var parts = topic.split('/');
if (parts.length < 4 || parts[0] !== 'tipa') {
    node.warn('[OBJ Inbound] skip invalid topic: ' + topic);
    return null;
}

var object_type = parts[parts.length - 1];

var data = msg.payload;
if (typeof data === 'string') {
    try { data = JSON.parse(data); }
    catch(e) { node.warn('[OBJ Inbound] invalid JSON: ' + topic); return null; }
}
if (!data || typeof data !== 'object') {
    node.warn('[OBJ Inbound] non-object payload: ' + topic);
    return null;
}

// Step 1: Load mapping for this object_type (default mapping)
msg._obj_type = object_type;
msg._obj_data = data;
msg._obj_topic = topic;
msg.query = 'SELECT id_path FROM public.object_mappings WHERE object_type_id = $1 AND mapping_name = $2 LIMIT 1';
msg.params = [object_type, 'default'];
msg.payload = null;
return msg;

var req = msg.req || {};
var object_type = req.params && req.params.object_type;
var body = req.body || {};
var mappingName = (req.query && req.query.mapping) || 'default';

if (!object_type) {
    msg.statusCode = 400;
    msg.payload = JSON.stringify({ error: 'Missing object_type in URL' });
    msg.headers = { 'Content-Type': 'application/json' };
    msg._skip = true;
    return msg;
}

if (!body || typeof body !== 'object' || Object.keys(body).length === 0) {
    msg.statusCode = 400;
    msg.payload = JSON.stringify({
        error: 'Body must contain search field as JSON',
        example: '{ "invoice_no": "00001619" }',
        hint: 'Use field names defined in mapping Rules'
    });
    msg.headers = { 'Content-Type': 'application/json' };
    msg._skip = true;
    return msg;
}

// First: load mapping (rules + id_path) to translate field name → JSON path
msg.query = 'SELECT rules, id_path FROM public.object_mappings WHERE object_type_id = $1 AND mapping_name = $2';
msg.params = [object_type, mappingName];
msg.payload = null;
msg._ctx = { object_type: object_type, body: body, mappingName: mappingName };
return msg;

if (msg._skip) return msg;

var rows = msg.payload || [];
var ctx  = msg._ctx || {};

if (!rows.length) {
    msg.statusCode = 404;
    msg.headers    = { 'Content-Type':'application/json' };
    msg.payload    = JSON.stringify({
        error:       'Object not found',
        object_type: ctx.object_type,
        searched_by: ctx.searchField,
        value:       ctx.searchValue
    });
    return msg;
}

function getPath(obj, path) {
    if (!obj || !path) return null;
    var parts = String(path).split('.');
    var cur = obj;
    for (var i = 0; i < parts.length; i++) {
        if (cur == null) return null;
        var key = parts[i];
        var m = key.match(/^(.+?)\[(\d+)\]$/);
        if (m) { cur = cur[m[1]]; if (Array.isArray(cur)) cur = cur[parseInt(m[2])]; }
        else   { cur = cur[key]; }
    }
    return cur == null ? null : cur;
}

var rules = ctx.rules || [];
var results = rows.map(function(row) {
    var content = row.content_object;
    if (typeof content === 'string') { try { content = JSON.parse(content); } catch(e) {} }
    var mappedFields = null;
    if (rules.length) {
        mappedFields = {};
        rules.forEach(function(r) {
            if (r.field && r.path) {
                var v = getPath(content, r.path);
                if (r.type === 'number'  && v != null) v = Number(v);
                if (r.type === 'boolean' && v != null) v = !!v;
                mappedFields[r.field] = v;
            }
        });
    }
    return {
        object_id:     row.object_id,
        created_at:    row.created_at,
        updated_at:    row.updated_at,
        mapped_fields: mappedFields,
        raw:           content
    };
});

msg.statusCode = 200;
msg.headers    = { 'Content-Type':'application/json' };
msg.payload    = JSON.stringify({
    object_type: ctx.object_type,
    table:       ctx.table,
    searched_by: ctx.searchField,
    value:       ctx.searchValue,
    count:       results.length,
    data:        results.length === 1 ? results[0] : results
});
return msg;

// MQTT inbound: extract key_value via mapping id_path, UPSERT into public.uns_obj_<type>
var object_type = msg._obj_type;
var data        = msg._obj_data;
var topic       = msg._obj_topic;
var rows        = msg.payload || [];

function getPath(obj, path) {
    if (!obj || !path) return null;
    var parts = String(path).split('.');
    var cur = obj;
    for (var i = 0; i < parts.length; i++) {
        if (cur == null) return null;
        var key = parts[i];
        var m = key.match(/^(.+?)\[(\d+)\]$/);
        if (m) { cur = cur[m[1]]; if (Array.isArray(cur)) cur = cur[parseInt(m[2])]; }
        else   { cur = cur[key]; }
    }
    return cur == null ? null : cur;
}

var id_path = rows.length ? rows[0].id_path : null;
if (!id_path) {
    node.warn('[OBJ Inbound] no mapping for ' + object_type + ' → skip');
    return null;
}
var key_value = getPath(data, id_path);
if (key_value === null || key_value === undefined || key_value === '') {
    node.warn('[OBJ Inbound] cannot extract key_value via "' + id_path + '" for ' + object_type);
    return null;
}
key_value = String(key_value);

var safe = String(object_type).toLowerCase().replace(/[^a-z0-9_]/g, '_');
var tbl  = 'uns_obj_' + safe;

msg.query = 'INSERT INTO public.' + tbl + ' (key_value, attribute) ' +
            'VALUES ($1::varchar, $2::jsonb) ' +
            'ON CONFLICT (key_value) DO UPDATE SET ' +
            '  attribute  = EXCLUDED.attribute, ' +
            '  updated_at = NOW()';
msg.params = [key_value, JSON.stringify(data)];
msg.payload = null;

delete msg._obj_type; delete msg._obj_data; delete msg._obj_topic;
node.warn('[OBJ Inbound] public.' + tbl + '/' + key_value + ' ← ' + topic);
return msg;

// UI seed → upsert into public.uns_obj_<type>
if (msg._seed_type) {
    var object_type = msg._seed_type;
    var content     = msg._seed_content;
    var rows        = msg.payload || [];

    function getPath(obj, path) {
        if (!obj || !path) return null;
        var parts = String(path).split('.');
        var cur = obj;
        for (var i = 0; i < parts.length; i++) {
            if (cur == null) return null;
            var key = parts[i];
            var m = key.match(/^(.+?)\[(\d+)\]$/);
            if (m) { cur = cur[m[1]]; if (Array.isArray(cur)) cur = cur[parseInt(m[2])]; }
            else   { cur = cur[key]; }
        }
        return cur == null ? null : cur;
    }

    var id_path = rows.length ? rows[0].id_path : null;
    if (!id_path) {
        node.send({ topic:'obj-ingest-result', payload:{ ok:false,
            msg:'No mapping defined for ' + object_type + '. Save mapping (with id_path) first.' }});
        return null;
    }
    var key_value = getPath(content, id_path);
    if (key_value === null || key_value === undefined || key_value === '') {
        node.send({ topic:'obj-ingest-result', payload:{ ok:false,
            msg:'Cannot extract key_value via path: ' + id_path }});
        return null;
    }
    key_value = String(key_value);

    var safe = String(object_type).toLowerCase().replace(/[^a-z0-9_]/g, '_');
    var tbl  = 'uns_obj_' + safe;

    msg.query = 'INSERT INTO public.' + tbl + ' (key_value, attribute) ' +
                'VALUES ($1::varchar, $2::jsonb) ' +
                'ON CONFLICT (key_value) DO UPDATE SET ' +
                '  attribute  = EXCLUDED.attribute, ' +
                '  updated_at = NOW()';
    msg.params = [key_value, JSON.stringify(content)];
    msg.payload = null;
    msg._ingest_result = { ok:true, msg:'Saved public.' + tbl + '/' + key_value + ' (via ' + id_path + ')' };
    delete msg._seed_type; delete msg._seed_content;
    node.warn('[OBJ Seed] public.' + tbl + '/' + key_value);
    return msg;
}
return msg;

if (msg._skip) return msg;

var ctx  = msg._ctx || {};
var rows = msg.payload || [];

if (!rows.length) {
    msg.statusCode = 404;
    msg.payload = JSON.stringify({
        error: 'No mapping defined for object_type: ' + ctx.object_type,
        hint:  'Define mapping via UI first'
    });
    msg.headers = { 'Content-Type': 'application/json' };
    msg._skip = true;
    return msg;
}

var mapping = rows[0];
var rules   = mapping.rules;
if (typeof rules === 'string') { try { rules = JSON.parse(rules); } catch(e) { rules = []; } }
rules = rules || [];
var id_path = mapping.id_path || '';

var body = ctx.body || {};
var searchKeys = Object.keys(body);
if (!searchKeys.length) {
    msg.statusCode = 400;
    msg.payload = JSON.stringify({ error:'Empty body' });
    msg.headers = { 'Content-Type':'application/json' };
    msg._skip = true;
    return msg;
}

var searchField = searchKeys[0];
var searchValue = body[searchField];

var resolvedPath = null;
var useKeyColumn = false;

// Accept legacy 'object_id' or new 'key_value' as direct PK lookup
if (searchField === 'object_id' || searchField === 'key_value') {
    useKeyColumn = true;
} else {
    for (var i = 0; i < rules.length; i++) {
        if (rules[i].field === searchField) { resolvedPath = rules[i].path; break; }
    }
    if (!resolvedPath && id_path) {
        var idPathParts = id_path.split('.');
        var idPathLastSeg = idPathParts[idPathParts.length - 1];
        if (searchField === idPathLastSeg) useKeyColumn = true;
    }
    if (!resolvedPath && !useKeyColumn) {
        msg.statusCode = 400;
        msg.payload = JSON.stringify({
            error: 'Unknown search field: ' + searchField,
            available_fields: rules.map(function(r){return r.field;}).concat(['object_id','key_value']),
            hint: 'Define field in mapping Rules first'
        });
        msg.headers = { 'Content-Type':'application/json' };
        msg._skip = true;
        return msg;
    }
}

var safe = String(ctx.object_type).toLowerCase().replace(/[^a-z0-9_]/g, '_');
var tbl  = 'uns_obj_' + safe;

if (useKeyColumn) {
    msg.query = "SELECT key_value AS object_id, attribute AS content_object, " +
                "created_at::text AS created_at, updated_at::text AS updated_at " +
                "FROM public." + tbl + " WHERE key_value = $1";
    msg.params = [String(searchValue)];
} else {
    var pathParts = resolvedPath.split('.').map(function(p){
        var m = p.match(/^(.+?)\[(\d+)\]$/);
        return m ? [m[1], m[2]] : [p];
    }).reduce(function(a,b){ return a.concat(b); }, []);
    var pgPath = '{' + pathParts.join(',') + '}';
    msg.query = "SELECT key_value AS object_id, attribute AS content_object, " +
                "created_at::text AS created_at, updated_at::text AS updated_at " +
                "FROM public." + tbl + " WHERE attribute #>> $1 = $2";
    msg.params = [pgPath, String(searchValue)];
}

msg._ctx.rules         = rules;
msg._ctx.searchField   = searchField;
msg._ctx.searchValue   = searchValue;
msg._ctx.resolvedPath  = resolvedPath;
msg._ctx.useKeyColumn  = useKeyColumn;
msg._ctx.table         = tbl;
msg.payload = null;
node.warn('[API] public.' + tbl + ' by ' + searchField + '=' + searchValue);
return msg;

var ev = msg.topic;
if (ev === 'obj-save-uns-cfg') {
    var cfg = {
        enterprise: 'tipa',
        site: (msg.payload && msg.payload.site) || 'hcm',
        area: (msg.payload && msg.payload.area) || 'plant1'
    };
    flow.set('uns_cfg', cfg);
    global.set('uns_cfg', cfg);  // also global so other tabs see it
    node.warn('[UNS Cfg] saved site=' + cfg.site + ' area=' + cfg.area);
    msg.topic = 'obj-uns-cfg-saved';
    msg.payload = cfg;
    return msg;
}
if (ev === 'obj-load-uns-cfg') {
    var c = flow.get('uns_cfg') || global.get('uns_cfg') || { enterprise:'tipa', site:'hcm', area:'plant1' };
    msg.topic = 'obj-uns-cfg';
    msg.payload = c;
    return msg;
}
return null;

// Initialize default UNS config if not set yet
var cur = flow.get('uns_cfg');
if (!cur) {
    var def = { enterprise:'tipa', site:'hcm', area:'plant1' };
    flow.set('uns_cfg', def);
    global.set('uns_cfg', def);
    node.warn('[UNS Cfg] initialized defaults');
}

// Find tables due for sync (enabled, interval elapsed)
msg.query = "SELECT jde_table, lower(pg_table) AS pg_table, oracle_schema, " +
            "       ts_col, last_max_cursor, interval_sec " +
            "FROM public.inc_sync_schedules " +
            "WHERE enabled = true " +
            "  AND (last_run_at IS NULL OR last_run_at < NOW() - (interval_sec || ' seconds')::interval)";
msg.params  = [];
msg.payload = null;
return msg;

var rows = msg.payload || [];
if (!rows.length) return null;
node.warn('[INC] ' + rows.length + ' table(s) due for sync');
rows.forEach(function(r) {
    node.send({
        _inc_meta: {
            jdeTable:    r.jde_table,
            pgTable:     String(r.pg_table || '').toLowerCase(),  // ALWAYS lowercase
            oraSchema:   r.oracle_schema || 'SYSTEM',
            tsCol:       String(r.ts_col || 'glupmj').toLowerCase(),
            cursorFrom:  parseInt(r.last_max_cursor || 0, 10),
            intervalSec: r.interval_sec || 300,
            startedAt:   new Date()
        }
    });
});
return null;

var m = msg._inc_meta || {};

function clean(s) { return String(s || '').replace(/[^A-Za-z0-9_$]/g, ''); }

// jde_table có thể là raw "F4311" hoặc đã có prefix → strip về raw
var rawTable = clean(m.jdeTable).toUpperCase().replace(/^V2_PRO_/, '');
var tsCol    = clean(m.tsCol || 'glupmj');

if (!rawTable || !tsCol) {
    node.error('[INC] Missing/invalid identifier — jdeTable=' + rawTable + ' tsCol=' + tsCol, msg);
    return null;
}

// ── ORACLE NAMING RULES ──
// 1. Mọi bảng đều thêm prefix V2_PRO_
// 2. Schema:
//    - F0911            → SYSTEM
//    - tất cả còn lại   → TIPA_ESB
var schema;
if (rawTable === 'F0911') {
    schema = 'SYSTEM';
} else {
    schema = 'TIPA_ESB';
}
var oraTable = 'V2_PRO_' + rawTable;

// Build query — KHÔNG có dấu ; ở cuối (ORA-00911)
// Oracle nonquoted alias không được start bằng `_`
var sql = 'SELECT t.* FROM ' +
          schema + '.' + oraTable + ' t ' +
          'WHERE t.' + tsCol + ' >= :1 AND ROWNUM <= 5000 ' +
          'ORDER BY t.' + tsCol + ' ASC';

// DEFENSIVE: strip mọi `;` và whitespace ở cuối
sql = sql.replace(/[;\s]+$/, '');

msg.query   = sql;
msg.payload = [parseInt(m.cursorFrom || 0, 10)];
node.warn('[INC] ' + schema + '.' + oraTable + ' fetch where ' + tsCol +
          ' >= ' + msg.payload[0]);
return msg;

// Nguồn Oracle đã gỡ cho deployment này (JDE giả lập bằng Postgres mock).
// Trả 0 dòng để luồng Incremental không lỗi khi bị trigger.
node.warn("Oracle delta-fetch disabled: no Oracle source (mock deployment)");
msg.payload = [];
return msg;

var m    = msg._inc_meta;
var rows = msg.payload || [];

// KEY_MAP — composite primary keys per JDE table (PG-side lowercase)
var KEY_MAP = {
    F0911:  ['gldct','gldoc','glkco','gljeln','gllt','glextl'],
    F43199: ['pddoco','pdkcoo','pddcto','pdlnid'],
    F43099: ['prdoco','prkcoo','prdcto','prlnid'],
    F0901:  ['gmmcu','gmobj','gmsub','gmco'],
    F0101:  ['aban8'],
    F4101:  ['imitm','imlitm'],
    F4102:  ['iblitm','ibmcu','ibstkt'],
    F4311:  ['pddoco','pdkcoo','pddcto','pdlnid','pdsfxo'],
    F4801:  ['wadoco','watyps'],
    F0411:  ['rpkco','rpdoc','rpdct','rpsfx','rpsfxe'],
    F4111:  ['ilkcoo','ildoco','ildcto','illnid'],
    F3002:  ['ixkit','ixmmcu','ixitm','ixcpit'],
    F3003:  ['irtrt','irkit','irmmcu','iropsq'],
    F4301:  ['phdoco','phkcoo','phdcto']
};

if (!rows.length) {
    msg.query = "UPDATE public.inc_sync_schedules " +
                "SET last_run_at = NOW(), last_rows_synced = 0, last_status = $1 " +
                "WHERE jde_table = $2";
    msg.params = ['no_changes', m.jdeTable];
    msg.payload = null;
    msg._inc_done = { rows: 0, newCursor: m.cursorFrom };
    msg._inc_rows = [];
    node.warn('[INC] ' + m.jdeTable + ' no new rows');
    return msg;
}

var jdeTable = String(m.jdeTable || '').replace(/^v2_pro_/i, '').toUpperCase();
var keys = KEY_MAP[jdeTable];
if (!keys || !keys.length) {
    node.error('[INC] No KEY_MAP for ' + jdeTable + '. Add to KEY_MAP in this function.', msg);
    return null;
}

function lc(s) { return String(s || '').toLowerCase(); }
var newCursor = m.cursorFrom;
var tsColLc   = lc(m.tsCol);

var cleaned = rows.map(function(r) {
    var lcRow = {};
    for (var k in r) lcRow[lc(k)] = r[k];
    var c = parseInt(lcRow[tsColLc] || 0, 10);
    if (c > newCursor) newCursor = c;
    return lcRow;
});

var cols       = Object.keys(cleaned[0]);
var quotedCols = cols.map(function(c) { return '"' + c + '"'; }).join(',');
var quotedKeys = keys.map(function(c) { return '"' + c + '"'; }).join(',');
var updateSet  = cols.filter(function(c) { return keys.indexOf(c) === -1; })
                     .map(function(c) { return '"' + c + '"=EXCLUDED."' + c + '"'; }).join(',');

var allParams = [];
var valuesSql = cleaned.map(function(row) {
    var vs = cols.map(function(c) {
        allParams.push(row[c] == null ? null : String(row[c]));
        return '$' + allParams.length;
    });
    return '(' + vs.join(',') + ')';
}).join(',');

var pgTbl = String(m.pgTable || '').toLowerCase();

// ── FIX 42P10 + 42601 ──
// Ora2Pg không tạo PK → ON CONFLICT cần unique constraint.
// CREATE UNIQUE INDEX IF NOT EXISTS — idempotent, deterministic name.
// PHẢI tách thành 2 messages riêng vì pg extended protocol KHÔNG cho multi-statement
// khi có placeholders ($1...$N). Cả 2 đi qua cùng PG node tuần tự:
//   Message 1 (no params, pure DDL):  CREATE UNIQUE INDEX IF NOT EXISTS ...
//   Message 2 (with params, INSERT):  INSERT ... ON CONFLICT DO UPDATE
var idxName = 'uniq_' + pgTbl + '_' + keys.join('_');
if (idxName.length > 60) idxName = idxName.slice(0, 60);  // PG 63-char limit

// Wrap CREATE INDEX trong DO block để chạy idempotent qua extended protocol
var msgDdl = {
    query:
        "DO $do$ BEGIN " +
        "  EXECUTE format('CREATE UNIQUE INDEX IF NOT EXISTS %I ON public.%I (" + quotedKeys + ")', " +
        "                 '" + idxName + "', '" + pgTbl + "'); " +
        "END $do$;",
    params:  [],
    payload: null,
    _inc_ddl_only: true   // marker — finalize node sẽ skip
};

// Message INSERT/UPSERT chính
var msgIns = {
    query:
        'INSERT INTO public."' + pgTbl + '" (' + quotedCols + ') VALUES ' + valuesSql +
        ' ON CONFLICT (' + quotedKeys + ') DO UPDATE SET ' +
        (updateSet || '"' + cols[0] + '"=EXCLUDED."' + cols[0] + '"'),
    params:  allParams,
    payload: null,
    _inc_meta: m,
    _inc_done: { rows: cleaned.length, newCursor: newCursor },
    _inc_rows: cleaned
};

node.warn('[INC] ' + m.jdeTable + ' DDL→idx + UPSERT ' + cleaned.length + ' rows → public.' + pgTbl +
          ', newCursor=' + newCursor);
node.send(msgDdl);
return msgIns;

// Skip DDL-only messages (e.g. CREATE INDEX gửi từ fn_inc_upsert)
if (msg._inc_ddl_only) return null;

var m      = msg._inc_meta;
var done   = msg._inc_done || { rows: 0, newCursor: m.cursorFrom };
var status = msg.error ? 'error' : 'ok';
var errMsg = msg.error ? String(msg.error).slice(0, 200) : null;

// FIX 42601: pg extended protocol KHÔNG cho multi-statement với params.
// Tách thành 2 messages tuần tự (cùng đi qua pg_inc_finalize node).
var msgUpd = {
    query:
        "UPDATE public.inc_sync_schedules SET last_max_cursor = $1, last_run_at = NOW(), " +
        "       last_rows_synced = $2, last_status = $3, updated_at = NOW() " +
        "WHERE jde_table = $4",
    params: [done.newCursor, done.rows, status, m.jdeTable],
    payload: null,
    _inc_ddl_only: true   // mark to suppress duplicate downstream processing
};

var msgLog = {
    query:
        "INSERT INTO public.inc_sync_log " +
        "  (jde_table, started_at, finished_at, cursor_from, cursor_to, rows_synced, status, error_msg) " +
        "VALUES ($1, $2, NOW(), $3, $4, $5, $6, $7)",
    params: [m.jdeTable, m.startedAt.toISOString(), m.cursorFrom,
             done.newCursor, done.rows, status, errMsg],
    payload: null
};

node.send(msgUpd);
return msgLog;

var t = msg.topic;
// Skip echoes
if (['inc-tables','inc-logs','inc-saved','inc-confirm-result'].indexOf(t) >= 0) return null;

if (t === 'inc-list-tables')   return [msg, null, null, null, null, null, null, null];
if (t === 'inc-list-logs')     return [null, msg, null, null, null, null, null, null];
if (t === 'inc-save-table')    return [null, null, msg, null, null, null, null, null];
if (t === 'inc-toggle')        return [null, null, null, msg, null, null, null, null];
if (t === 'inc-run-now')       return [null, null, null, null, msg, null, null, null];
if (t === 'inc-reset-cursor')  return [null, null, null, null, null, msg, null, null];
if (t === 'inc-delete')        return [null, null, null, null, null, null, msg, null];
if (t === 'inc-confirm-table') return [null, null, null, null, null, null, null, msg];
return null;

msg.query = "SELECT jde_table, lower(pg_table) AS pg_table, oracle_schema, ts_col, " +
            "       interval_sec, last_max_cursor, enabled, " +
            "       last_run_at::text AS last_run_at, last_rows_synced, last_status, " +
            "       updated_at::text AS updated_at " +
            "FROM public.inc_sync_schedules " +
            "ORDER BY jde_table";
msg.params  = [];
msg.payload = null;
return msg;

msg.topic   = 'inc-tables';
msg.payload = msg.payload || [];
return msg;

msg.query = "SELECT id, jde_table, " +
            "       started_at::text AS started_at, finished_at::text AS finished_at, " +
            "       cursor_from, cursor_to, rows_synced, status, error_msg " +
            "FROM public.inc_sync_log " +
            "ORDER BY started_at DESC LIMIT 30";
msg.params  = [];
msg.payload = null;
return msg;

var d = msg.payload || {};
msg.query = "UPDATE public.inc_sync_schedules SET enabled = $1, updated_at = NOW() WHERE jde_table = $2";
msg.params = [!!d.enabled, d.jde_table];
msg.payload = null;
return msg;

var d = msg.payload || {};
msg.query = "UPDATE public.inc_sync_schedules SET last_run_at = NULL WHERE jde_table = $1";
msg.params = [d.jde_table];
msg.payload = null;
node.warn('[INC] Run now requested for ' + d.jde_table);
return msg;

var d = msg.payload || {};
msg.query = "UPDATE public.inc_sync_schedules SET last_max_cursor = $1, last_run_at = NULL, updated_at = NOW() WHERE jde_table = $2";
msg.params = [parseInt(d.cursor || 0, 10), d.jde_table];
msg.payload = null;
return msg;

var d = msg.payload || {};
msg.query = "DELETE FROM public.inc_sync_schedules WHERE jde_table = $1";
msg.params = [d.jde_table];
msg.payload = null;
return msg;

msg.query = [
    "CREATE TABLE IF NOT EXISTS public.jde_table_mappings (" +
    "  table_name VARCHAR(100) PRIMARY KEY, " +
    "  mapping    JSONB NOT NULL, " +
    "  created_at TIMESTAMP DEFAULT NOW(), " +
    "  updated_at TIMESTAMP DEFAULT NOW()" +
    ");",
    "ALTER TABLE public.jde_table_mappings ADD COLUMN IF NOT EXISTS mqtt_enabled BOOLEAN DEFAULT false;",
    "ALTER TABLE public.jde_table_mappings ADD COLUMN IF NOT EXISTS mqtt_topic   VARCHAR(255);",
    "ALTER TABLE public.jde_table_mappings ADD COLUMN IF NOT EXISTS source_mode  VARCHAR(10) DEFAULT 'table';",
    "ALTER TABLE public.jde_table_mappings ADD COLUMN IF NOT EXISTS custom_sql   TEXT DEFAULT '';"
].join(' ');
msg.params  = [];
msg.payload = null;
node.warn('[JDE v2] DDL public.jde_table_mappings (+ source_mode, custom_sql)');
return msg;

var t = msg.topic || '';
if (t === 'jde-list-tables')        return [msg, null, null, null, null, null, null];
if (t === 'jde-list-cols')          return [null, msg, null, null, null, null, null];
if (t === 'jde-load-mapping')       return [null, null, msg, null, null, null, null];
if (t === 'jde-save-mapping')       return [null, null, null, msg, null, null, null];
if (t === 'jde-api-test')           return [null, null, null, null, msg, null, null];
if (t === 'jde-fetch-custom-cols')  {
    node.warn('[DISPATCH] custom-cols → routing to probe chain');
    return [null, null, null, null, null, msg, null];
}
if (t === 'jde-list-mappings')      return [null, null, null, null, null, null, msg];
return null;

// List enabled tables FROM public.inc_sync_schedules
// pg_table luôn lowercase
msg.query = "SELECT jde_table, lower(pg_table) AS pg_table " +
            "FROM public.inc_sync_schedules " +
            "WHERE enabled = true " +
            "ORDER BY pg_table";
msg.params  = [];
msg.payload = null;
return msg;

var d   = msg.payload || {};
var tbl = String(d.table || '').toLowerCase().replace(/[^a-z0-9_]/g, '');
if (!tbl) return null;
msg.query  = "SELECT column_name FROM information_schema.columns " +
             "WHERE table_schema = 'public' AND table_name = $1 " +
             "ORDER BY ordinal_position";
msg.params = [tbl];
msg.payload = null;
return msg;

var d = msg.payload || {};
if (!d.table) return null;
msg.query  = "SELECT mapping, mqtt_enabled, mqtt_topic, " +
             "       COALESCE(source_mode,'table') AS source_mode, " +
             "       COALESCE(custom_sql,'') AS custom_sql " +
             "FROM public.jde_table_mappings WHERE table_name = $1";
msg.params = [String(d.table).toLowerCase()];
msg._tbl   = d.table;
msg.payload = null;
return msg;

var rows = msg.payload || [];
var mapping = [], mqtt_enabled = false, mqtt_topic = '', source_mode = 'table', custom_sql = '';
if (rows.length) {
    var raw = rows[0].mapping;
    if (typeof raw === 'string') { try { raw = JSON.parse(raw); } catch(e) { raw = []; } }
    mapping       = Array.isArray(raw) ? raw : [];
    mqtt_enabled  = !!rows[0].mqtt_enabled;
    mqtt_topic    = rows[0].mqtt_topic || '';
    source_mode   = rows[0].source_mode || 'table';
    custom_sql    = rows[0].custom_sql  || '';
}
msg.topic   = 'jde-mapping-loaded';
msg.payload = {
    table:        msg._tbl,
    mapping:      mapping,
    mqtt_enabled: mqtt_enabled,
    mqtt_topic:   mqtt_topic,
    source_mode:  source_mode,
    custom_sql:   custom_sql
};
return msg;

var d = msg.payload || {};
if (!d.table || !Array.isArray(d.mapping)) return null;
var clean = d.mapping
    .filter(function(m) { return m && m.col && m.name; })
    .map(function(m)    {
        return {
            col:  String(m.col).toLowerCase(),
            name: String(m.name),
            type: String(m.type || 'text').toLowerCase()
        };
    });

var topic      = String(d.mqtt_topic || '').trim();
var sourceMode = (d.source_mode === 'custom') ? 'custom' : 'table';
var customSql  = String(d.custom_sql || '').trim().replace(/;+\s*$/, '');

msg.query =
    "INSERT INTO public.jde_table_mappings " +
    "  (table_name, mapping, mqtt_enabled, mqtt_topic, source_mode, custom_sql) " +
    "VALUES ($1, $2::jsonb, $3, $4, $5, $6) " +
    "ON CONFLICT (table_name) DO UPDATE SET " +
    "  mapping      = EXCLUDED.mapping, " +
    "  mqtt_enabled = EXCLUDED.mqtt_enabled, " +
    "  mqtt_topic   = EXCLUDED.mqtt_topic, " +
    "  source_mode  = EXCLUDED.source_mode, " +
    "  custom_sql   = EXCLUDED.custom_sql, " +
    "  updated_at   = NOW()";
msg.params = [
    String(d.table).toLowerCase(),
    JSON.stringify(clean),
    !!d.mqtt_enabled,
    topic || null,
    sourceMode,
    customSql
];
msg._tbl   = d.table;
msg._cnt   = clean.length;
msg.payload = null;
node.warn('[JDE v2] Save ' + clean.length + ' cols for ' + d.table + ' (mode=' + sourceMode + ')');
return msg;

msg.topic = 'jde-mapping-saved';
if (msg.error) {
    msg.payload = { ok:false, msg: 'Save failed: ' + String(msg.error).slice(0, 200) };
} else {
    msg.payload = { ok:true, msg: 'Saved ' + msg._cnt + ' mappings for ' + msg._tbl };
}
return msg;

var d = msg.payload || {};
if (!d.table) {
    node.send({ topic:'jde-api-result', payload:{ error:'Missing table' }});
    return null;
}
msg.query  = "SELECT mapping, COALESCE(source_mode,'table') AS source_mode, " +
             "       COALESCE(custom_sql,'') AS custom_sql " +
             "FROM public.jde_table_mappings WHERE table_name = $1";
msg.params = [String(d.table).toLowerCase()];
msg._req = d;
msg._isUiTest = true;
msg.payload = null;
return msg;

// Build SELECT — hỗ trợ cả 'table' mode và 'custom' mode
var rows = msg.payload || [];
var req  = msg._req || {};

var mappingRow = rows[0];
if (!mappingRow) {
    msg.statusCode = 404;
    msg._respJson = { error: 'No mapping for table: ' + (req.table || ''), hint: 'Define mapping in JDE → UNS UI first' };
    msg.query = "SELECT 1 WHERE false"; msg.params = [];
    return msg;
}

var mapping    = mappingRow.mapping;
var sourceMode = mappingRow.source_mode || 'table';
var customSql  = String(mappingRow.custom_sql || '').trim().replace(/;+\s*$/, '');

if (typeof mapping === 'string') { try { mapping = JSON.parse(mapping); } catch(e) { mapping = []; } }
mapping = Array.isArray(mapping) ? mapping : [];
if (!mapping.length) {
    msg.statusCode = 400;
    msg._respJson = { error: 'Empty mapping' };
    msg.query = "SELECT 1 WHERE false"; msg.params = [];
    return msg;
}

var safeCols = mapping
    .map(function(m){ return String(m.col || '').toLowerCase().replace(/[^a-z0-9_]/g, ''); })
    .filter(function(c){ return c; });
if (!safeCols.length) {
    msg.statusCode = 500;
    msg._respJson = { error: 'Mapping has no valid columns' };
    msg.query = "SELECT 1 WHERE false"; msg.params = [];
    return msg;
}

var quotedCols = safeCols.map(function(c){ return '"' + c + '"'; }).join(', ');

var where  = (req.where && typeof req.where === 'object' && !Array.isArray(req.where)) ? req.where : {};
var conds  = [];
var params = [];
Object.keys(where).forEach(function(k) {
    var col = String(k).toLowerCase().replace(/[^a-z0-9_]/g, '');
    if (!col) return;
    params.push(String(where[k]));
    conds.push('"' + col + '"::text = $' + params.length);
});

var limit = parseInt(req.limit, 10);
if (!limit || limit < 1) limit = 10;
if (limit > 500) limit = 500;

if (sourceMode === 'custom' && customSql) {
    // Wrap user query, project only mapped cols, apply WHERE/LIMIT
    msg.query = 'SELECT ' + quotedCols + ' FROM (' + customSql + ') AS inner_q'
              + (conds.length ? ' WHERE ' + conds.join(' AND ') : '')
              + ' LIMIT ' + limit;
} else {
    var tbl = String(req.table || '').toLowerCase().replace(/[^a-z0-9_]/g, '');
    if (!tbl) {
        msg.statusCode = 400;
        msg._respJson = { error: 'Missing/invalid table' };
        msg.query = "SELECT 1 WHERE false"; msg.params = [];
        return msg;
    }
    msg.query = 'SELECT ' + quotedCols + ' FROM public."' + tbl + '"'
              + (conds.length ? ' WHERE ' + conds.join(' AND ') : '')
              + ' LIMIT ' + limit;
}
msg.params = params;
msg._mapping = mapping;
msg._tbl = req.table;
msg.payload = null;
return msg;

var rows = msg.payload || [];
var resp;

if (msg._respJson) {
    resp = msg._respJson;
} else {
    var mapping = msg._mapping || [];
    var byCol = {};
    mapping.forEach(function(m){
        if (m && m.col) byCol[String(m.col).toLowerCase()] = m;
    });

    function cast(v, type) {
        if (v == null) return null;
        if (type === 'number') { var n = Number(v); return isNaN(n) ? v : n; }
        if (type === 'date')   return String(v);
        return v;
    }

    var data = rows.map(function(r) {
        var o = {};
        Object.keys(r).forEach(function(c) {
            var rule = byCol[c];
            var nm   = (rule && rule.name) || c;
            var t    = (rule && rule.type) || 'text';
            o[nm] = cast(r[c], t);
        });
        return o;
    });
    resp = { table: msg._tbl, count: data.length, data: data };
}

if (msg._isUiTest) {
    msg.topic = 'jde-api-result';
    msg.payload = resp;
    return [msg, null];
}

