function b64url(b){return Buffer.from(b).toString('base64').replace(/\+/g,'-').replace(/\//g,'_').replace(/=+$/,'');}
function deny(){msg.statusCode=401;msg.headers={'Content-Type':'application/json'};msg.payload=JSON.stringify({error:'unauthenticated'});return [null,msg];}
var tok=getCookie(msg.req,'tipa_auth'); if(!tok) return deny();
var parts=String(tok).split('.'); if(parts.length!==2) return deny();
var expSig=b64url(crypto.createHmac('sha256',secret).update(parts[0]).digest());
if(expSig!==parts[1]) return deny();
var payload; try{ payload=JSON.parse(Buffer.from(parts[0].replace(/-/g,'+').replace(/_/g,'/'),'base64').toString()); }catch(e){ return deny(); }
if(payload.exp && Date.now()>payload.exp) return deny();
msg._user=payload; return [msg,null];

